import { useState, useRef, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const containerRef = useRef(null)

  const [activeTab, setActiveTab] = useState('design')

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [selectedSize, setSelectedSize] = useState('M')

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [uploadedFile, setUploadedFile] = useState(null)

  const [logoSize, setLogoSize] = useState(180)

  const [isDragging, setIsDragging] = useState(false)

  const [activePreset, setActivePreset] = useState('front')

  const [logoPosition, setLogoPosition] = useState({
    x: 50,
    y: 42
  })

  const [customerName, setCustomerName] = useState('')

  const [customerEmail, setCustomerEmail] = useState('')

  const [customerPhone, setCustomerPhone] = useState('')

  const [quantity, setQuantity] = useState('24')

  const [notes, setNotes] = useState('')

  useEffect(() => {

    const handleKeyDown = (e) => {

      const step = 1

      if (e.key === 'ArrowUp') {
        setLogoPosition(prev => ({
          ...prev,
          y: prev.y - step
        }))
      }

      if (e.key === 'ArrowDown') {
        setLogoPosition(prev => ({
          ...prev,
          y: prev.y + step
        }))
      }

      if (e.key === 'ArrowLeft') {
        setLogoPosition(prev => ({
          ...prev,
          x: prev.x - step
        }))
      }

      if (e.key === 'ArrowRight') {
        setLogoPosition(prev => ({
          ...prev,
          x: prev.x + step
        }))
      }

      if (e.key === '[') {
        setLogoSize(prev =>
          Math.max(prev - 5, 60)
        )
      }

      if (e.key === ']') {
        setLogoSize(prev =>
          Math.min(prev + 5, 400)
        )
      }
    }

    window.addEventListener(
      'keydown',
      handleKeyDown
    )

    return () => {

      window.removeEventListener(
        'keydown',
        handleKeyDown
      )
    }

  }, [])

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (file) {

      setUploadedFile(file)

      setUploadedLogo(
        URL.createObjectURL(file)
      )
    }
  }

  const removeLogo = () => {

    setUploadedLogo(null)

    setUploadedFile(null)
  }

  const handleMouseMove = (e) => {

    if (!isDragging) return

    const rect =
      containerRef.current.getBoundingClientRect()

    const x =
      ((e.clientX - rect.left) / rect.width) * 100

    const y =
      ((e.clientY - rect.top) / rect.height) * 100

    setLogoPosition({
      x,
      y
    })
  }

  const handleMouseUp = () => {
    setIsDragging(false)
  }

  const setPreset = (type) => {

    setActivePreset(type)

    if (type === 'front') {
      setLogoPosition({ x: 50, y: 42 })
      setLogoSize(180)
    }

    if (type === 'left-chest') {
      setLogoPosition({ x: 38, y: 30 })
      setLogoSize(90)
    }

    if (type === 'oversized') {
      setLogoPosition({ x: 50, y: 45 })
      setLogoSize(320)
    }

    if (type === 'back') {
      setLogoPosition({ x: 50, y: 42 })
      setLogoSize(260)
    }

    if (type === 'sleeve') {
      setLogoPosition({ x: 72, y: 33 })
      setLogoSize(70)
    }
  }

  return (

    <div
      className="h-screen bg-black text-white overflow-hidden"
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >

      <div className="grid grid-cols-1 xl:grid-cols-2 h-full">


        <div
          ref={containerRef}
          className="bg-[#0d0d0d] flex items-center justify-center relative p-6"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[650px]"
          />

          {uploadedLogo && (

            <img
              src={uploadedLogo}
              alt="logo"
              onMouseDown={() => setIsDragging(true)}
              className="absolute z-20 select-none mix-blend-screen opacity-90 drop-shadow-[0_0_20px_rgba(0,0,0,0.7)]"
              style={{
                width: `${logoSize}px`,
                top: `${logoPosition.y}%`,
                left: `${logoPosition.x}%`,
                transform: 'translate(-50%, -50%)',
                cursor: isDragging ? 'grabbing' : 'grab',
                filter: 'contrast(1.05) saturate(1.1)'
              }}
              draggable={false}
            />

          )}

        </div>


        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full">


          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

            <p className="text-yellow-500 mt-2 text-xl">
              Starting at ${product.price}
            </p>

          </div>


          <div className="grid grid-cols-4 border-b border-[#1d1d1d]">

            {[
              'design',
              'product',
              'contact',
              'summary'
            ].map((tab) => (

              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`py-5 text-xs uppercase font-black transition ${
                  activeTab === tab
                    ? 'bg-yellow-500 text-black'
                    : 'text-white border-r border-[#1d1d1d]'
                }`}
              >
                {tab}
              </button>

            ))}

          </div>


          <div className="flex-1 overflow-y-auto p-6">


            {activeTab === 'design' && (

              <div className="space-y-6">

                <div>

                  <h2 className="text-sm font-black mb-4">
                    Placement
                  </h2>

                  <div className="grid grid-cols-2 gap-3">

                    {[
                      'front',
                      'left-chest',
                      'oversized',
                      'back',
                      'sleeve'
                    ].map((item) => (

                      <button
                        key={item}
                        onClick={() => setPreset(item)}
                        className={`p-4 rounded-xl text-xs font-black ${
                          activePreset === item
                            ? 'bg-yellow-500 text-black'
                            : 'bg-[#111] border border-[#222]'
                        }`}
                      >
                        {item}
                      </button>

                    ))}

                  </div>

                </div>


                <div>

                  <h2 className="text-sm font-black mb-4">
                    Upload Logo
                  </h2>

                  <input
                    type="file"
                    accept="image/png,image/jpeg"
                    onChange={handleUpload}
                    className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
                  />

                </div>


                {uploadedLogo && (

                  <button
                    onClick={removeLogo}
                    className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
                  >

                    REMOVE LOGO

                  </button>

                )}


                <div>

                  <div className="flex justify-between mb-3">

                    <p className="text-xs text-white/60">
                      Logo Size
                    </p>

                    <p className="text-xs text-yellow-500 font-black">
                      {logoSize}px
                    </p>

                  </div>

                  <input
                    type="range"
                    min="60"
                    max="400"
                    value={logoSize}
                    onChange={(e) =>
                      setLogoSize(e.target.value)
                    }
                    className="w-full"
                  />

                </div>


                <div className="grid grid-cols-2 gap-4">

                  <div className="bg-[#111] border border-[#222] rounded-xl p-4 text-xs">

                    X Position:
                    <span className="text-yellow-500 ml-2">
                      {Math.round(logoPosition.x)}
                    </span>

                  </div>

                  <div className="bg-[#111] border border-[#222] rounded-xl p-4 text-xs">

                    Y Position:
                    <span className="text-yellow-500 ml-2">
                      {Math.round(logoPosition.y)}
                    </span>

                  </div>

                </div>


                <p className="text-[10px] text-white/40">
                  Arrow Keys = Move Logo • [ ] = Resize
                </p>

              </div>

            )}


            {activeTab === 'product' && (

              <div className="space-y-6">

                <div>

                  <h2 className="text-sm font-black mb-4">
                    Colors
                  </h2>

                  <div className="flex gap-3 flex-wrap">

                    {product.colors.map((color) => (

                      <button
                        key={color.name}
                        onClick={() =>
                          setSelectedColor(color)
                        }
                        className={`w-14 h-14 rounded-full border-4 ${
                          selectedColor.name === color.name
                            ? 'border-yellow-500'
                            : 'border-white'
                        }`}
                        style={{
                          backgroundColor: color.hex
                        }}
                      />

                    ))}

                  </div>

                </div>


                <div>

                  <h2 className="text-sm font-black mb-4">
                    Sizes
                  </h2>

                  <div className="grid grid-cols-3 gap-3">

                    {[
                      'S',
                      'M',
                      'L',
                      'XL',
                      '2XL',
                      '3XL'
                    ].map((size) => (

                      <button
                        key={size}
                        onClick={() =>
                          setSelectedSize(size)
                        }
                        className={`py-4 rounded-xl text-xs font-black ${
                          selectedSize === size
                            ? 'bg-yellow-500 text-black'
                            : 'bg-[#111] border border-[#222]'
                        }`}
                      >
                        {size}
                      </button>

                    ))}

                  </div>

                </div>


                <div>

                  <h2 className="text-sm font-black mb-4">
                    Quantity
                  </h2>

                  <input
                    type="number"
                    value={quantity}
                    onChange={(e) =>
                      setQuantity(e.target.value)
                    }
                    className="w-full bg-[#111] border border-[#222] rounded-xl p-4"
                  />

                </div>

              </div>

            )}


            {activeTab === 'contact' && (

              <div className="space-y-5">

                <input
                  type="text"
                  placeholder="Your Name"
                  value={customerName}
                  onChange={(e) =>
                    setCustomerName(e.target.value)
                  }
                  className="w-full bg-[#111] border border-[#222] rounded-xl p-4"
                />

                <input
                  type="email"
                  placeholder="Email Address"
                  value={customerEmail}
                  onChange={(e) =>
                    setCustomerEmail(e.target.value)
                  }
                  className="w-full bg-[#111] border border-[#222] rounded-xl p-4"
                />

                <input
                  type="text"
                  placeholder="Phone Number"
                  value={customerPhone}
                  onChange={(e) =>
                    setCustomerPhone(e.target.value)
                  }
                  className="w-full bg-[#111] border border-[#222] rounded-xl p-4"
                />

                <textarea
                  rows="5"
                  placeholder="Additional Notes"
                  value={notes}
                  onChange={(e) =>
                    setNotes(e.target.value)
                  }
                  className="w-full bg-[#111] border border-[#222] rounded-xl p-4"
                />

              </div>

            )}


            {activeTab === 'summary' && (

              <div className="space-y-4">

                <div className="bg-[#111] border border-[#222] rounded-2xl p-5 space-y-3 text-sm">

                  <p>
                    Product:
                    <span className="text-yellow-500 ml-2">
                      {product.name}
                    </span>
                  </p>

                  <p>
                    Color:
                    <span className="text-yellow-500 ml-2">
                      {selectedColor.name}
                    </span>
                  </p>

                  <p>
                    Size:
                    <span className="text-yellow-500 ml-2">
                      {selectedSize}
                    </span>
                  </p>

                  <p>
                    Quantity:
                    <span className="text-yellow-500 ml-2">
                      {quantity}
                    </span>
                  </p>

                  <p>
                    Placement:
                    <span className="text-yellow-500 ml-2">
                      {activePreset}
                    </span>
                  </p>

                  <p>
                    Logo Size:
                    <span className="text-yellow-500 ml-2">
                      {logoSize}px
                    </span>
                  </p>

                </div>


                <button
                  className="w-full bg-yellow-500 text-black py-5 rounded-2xl font-black"
                >

                  REQUEST QUOTE

                </button>

              </div>

            )}

          </div>

        </div>

      </div>

    </div>

  )
}
